import json, os, io, datetime
from flask import Flask, request, jsonify, send_file
import sqlite3
import pv_calculations as pvc

BASE_DIR = os.path.dirname(os.path.abspath(__file__))
app = Flask(__name__)

# Embedded Gridworks logo (offline PNG, base64) — used in PDF export.
LOGO_B64 = ""

DB = "/tmp/projects.db"

def get_db():
    conn = sqlite3.connect(DB)
    conn.row_factory = sqlite3.Row
    return conn

def init_db():
    try:
        with get_db() as db:
            db.execute("""
                CREATE TABLE IF NOT EXISTS projects (
                    id        INTEGER PRIMARY KEY AUTOINCREMENT,
                    name      TEXT NOT NULL,
                    inputs    TEXT NOT NULL,
                    results   TEXT,
                    cable_schedule TEXT,
                    created   TEXT NOT NULL,
                    updated   TEXT NOT NULL
                )
            """)
            db.commit()
    except Exception as e:
        print(f"DB init warning: {e}")

init_db()


# ── Helper: serve HTML file ───────────────────────────────────────────────────

def serve_html(filename):
    possible = [
        os.path.join(BASE_DIR, "templates", filename),
        os.path.join(os.getcwd(), "templates", filename),
        f"/opt/render/project/src/templates/{filename}",
    ]
    for path in possible:
        if os.path.exists(path):
            with open(path, "r", encoding="utf-8") as f:
                return f.read(), 200, {"Content-Type": "text/html; charset=utf-8"}
    return jsonify({
        "error": f"{filename} not found",
        "tried": possible,
        "BASE_DIR": BASE_DIR,
        "BASE_DIR_contents": os.listdir(BASE_DIR),
        "cwd": os.getcwd(),
        "cwd_contents": os.listdir(os.getcwd()),
    }), 500


