# ── API: System Sizing ────────────────────────────────────────────────────────

@app.route("/api/calculate/sizing", methods=["POST"])
def api_sizing():
    data = request.get_json(silent=True) or {}
    try:
        return jsonify({"ok": True, "result": pvc.calc_system_sizing(data)})
    except Exception as e:
        return jsonify({"ok": False, "error": str(e)}), 422


# ── API: Cable Schedule ───────────────────────────────────────────────────────

@app.route("/api/calculate/cable_schedule", methods=["POST"])
def api_cable_schedule():
    data = request.get_json(silent=True) or {}
    rows = data.get("rows", [])
    try:
        results = [pvc.calc_cable_row(r) for r in rows]
        n = len(results)
        total_ploss  = sum(r["ploss_w"]    for r in results)
        avg_loading  = sum(r["loading_pct"] for r in results) / n if n else 0
        # 3-phase total power loss = 3 × sum(I²R·L) converted to kW
        three_phase  = 3 * total_ploss
        # Average voltage drop across all runs
        avg_vdrop    = sum(r["vdrop_pct"]  for r in results) / n if n else 0
        return jsonify({
            "ok": True, "rows": results,
            "summary": {
                "total_ploss_w":   round(total_ploss, 2),
                "three_phase_w":   round(three_phase, 2),
                "avg_loading_pct": round(avg_loading, 4),
                "avg_mv_loss_pct": round(avg_vdrop, 4),
            }
        })
    except Exception as e:
        return jsonify({"ok": False, "error": str(e)}), 422


