# ── API: Projects ─────────────────────────────────────────────────────────────

@app.route("/api/projects", methods=["GET"])
def list_projects():
    try:
        rows = get_db().execute(
            "SELECT id, name, created, updated FROM projects ORDER BY updated DESC"
        ).fetchall()
        return jsonify([dict(r) for r in rows])
    except Exception:
        return jsonify([])

@app.route("/api/projects", methods=["POST"])
def save_project():
    data = request.get_json(silent=True) or {}
    now  = datetime.datetime.utcnow().isoformat()
    pid  = data.get("id")
    try:
        with get_db() as db:
            if pid:
                db.execute(
                    "UPDATE projects SET name=?,inputs=?,results=?,cable_schedule=?,updated=? WHERE id=?",
                    (data.get("name","Untitled"),
                     json.dumps(data.get("inputs",{})),
                     json.dumps(data.get("results",{})),
                     json.dumps(data.get("cable_schedule",[])),
                     now, pid)
                )
                db.commit()
                return jsonify({"ok": True, "id": pid, "msg": "Updated."})
            else:
                cur = db.execute(
                    "INSERT INTO projects (name,inputs,results,cable_schedule,created,updated) VALUES(?,?,?,?,?,?)",
                    (data.get("name","Untitled"),
                     json.dumps(data.get("inputs",{})),
                     json.dumps(data.get("results",{})),
                     json.dumps(data.get("cable_schedule",[])),
                     now, now)
                )
                db.commit()
                return jsonify({"ok": True, "id": cur.lastrowid, "msg": "Saved."})
    except Exception as e:
        return jsonify({"ok": False, "error": str(e)}), 500

@app.route("/api/projects/<int:pid>", methods=["GET"])
def load_project(pid):
    try:
        row = get_db().execute("SELECT * FROM projects WHERE id=?", (pid,)).fetchone()
        if not row:
            return jsonify({"ok": False, "error": "Not found"}), 404
        proj = dict(row)
        proj["inputs"]         = json.loads(proj["inputs"] or "{}")
        proj["results"]        = json.loads(proj["results"] or "{}")
        proj["cable_schedule"] = json.loads(proj["cable_schedule"] or "[]")
        return jsonify({"ok": True, "project": proj})
    except Exception as e:
        return jsonify({"ok": False, "error": str(e)}), 500

@app.route("/api/projects/<int:pid>", methods=["DELETE"])
def delete_project(pid):
    with get_db() as db:
        db.execute("DELETE FROM projects WHERE id=?", (pid,))
        db.commit()
    return jsonify({"ok": True})


# ── Cable run constants & helper (shared by PDF and Excel export) ─────────────

_CABLE_R = {
    '4/0 AL':0.100,'500 KCMIL AL':0.043,'750 KCMIL AL':0.029,
    '1000 KCMIL AL':0.023,'1250 KCMIL AL':0.018,
}
_CABLE_A_DB = {
    '4/0 AL':280,'500 KCMIL AL':445,'750 KCMIL AL':550,
    '1000 KCMIL AL':635,'1250 KCMIL AL':705,
}
_CABLE_A_IC = {
    '4/0 AL':230,'500 KCMIL AL':370,'750 KCMIL AL':460,
    '1000 KCMIL AL':530,'1250 KCMIL AL':590,
}

def _compute_cable_rows(cable_runs):
    """Return list of dicts with all computed fields for each cable run."""
    rows = []
    for row in (cable_runs or []):
        n    = float(row.get("n_pcs") or 0)
        kva  = float(row.get("pcs_kva") or 4400)
        kv   = float(row.get("ac_kv") or 34.5)
        cab  = row.get("cable_type", "4/0 AL")
        lft  = float(row.get("circuit_length_ft") or 0)
        inst = row.get("installation", "DIRECT BURY")
        cur  = (n * kva * 1000) / (1.73 * kv * 1000) if kv else 0
        amp  = (_CABLE_A_IC if inst == "IN CONDUIT" else _CABLE_A_DB).get(cab, 0)
        res  = _CABLE_R.get(cab, 0)
        load = cur / amp if amp else 0
        vd   = ((cur * (res / 1000) * lft) / (kv * 1000 / 1.732)) * 100 if kv else 0
        rows.append({
            "from_label":        row.get("from_label", ""),
            "to_label":          row.get("to_label", ""),
            "n_pcs":             row.get("n_pcs", ""),
            "pcs_kva":           row.get("pcs_kva", ""),
            "ac_kv":             row.get("ac_kv", ""),
            "cable_type":        cab,
            "circuit_length_ft": lft,
            "installation":      inst,
            "current_a":         round(cur, 2),
            "ampacity_a":        amp,
            "loading_pct":       round(load * 100, 2),
            "r_ohm_kft":         res,
            "v_drop_pct":        round(vd, 4),
        })
    return rows


# ── API: PDF Export ───────────────────────────────────────────────────────────

@app.route("/api/export/pdf", methods=["POST"])
def export_pdf():
    from reportlab.lib.pagesizes import letter
    from reportlab.lib import colors
    from reportlab.lib.units import inch
    from reportlab.platypus import (SimpleDocTemplate, Table, TableStyle,
                                    Paragraph, Spacer, HRFlowable, PageBreak, Image,
                                    KeepTogether)
    from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
    from reportlab.lib.enums import TA_CENTER, TA_RIGHT, TA_LEFT
    import urllib.request, tempfile, os

    data         = request.get_json(silent=True) or {}
    sizing       = data.get("sizing", {})
    ampacity     = data.get("ampacity", {})
    cable_runs   = data.get("cable_runs", [])
    cable_results= data.get("cable_results", [])
    feeder_table = data.get("feeder_table", [])
    cable_params = data.get("cable_params", {})
    project_name = data.get("project_name", "Solar PV Design")
    project_num  = data.get("project_number", "")
    engineer     = data.get("engineer", "")
    proj_date    = data.get("proj_date", datetime.date.today().isoformat())
    inputs       = data.get("inputs", {})

    from reportlab.lib.pagesizes import landscape as _ls
    buf = io.BytesIO()
    doc = SimpleDocTemplate(buf, pagesize=letter,
                            leftMargin=0.5*inch, rightMargin=0.5*inch,
                            topMargin=0.55*inch, bottomMargin=0.45*inch)
    W = doc.width   # full printable width — all tables stretch to fill this
    styl  = getSampleStyleSheet()
    # ── Gridworks brand palette (matches corporate report theme) ──────────────
    ORANGE = colors.HexColor("#E2792B")   # section headers, accent rules
    DORANGE= colors.HexColor("#C65A18")   # deep orange (strong accents)
    CHAR   = colors.HexColor("#404040")   # charcoal — titles, header text, body
    GOLD   = colors.HexColor("#F4A62A")   # table header fill
    CREAM  = colors.HexColor("#FBF3E6")   # light cream — alt rows / info block
    LGRAY = colors.HexColor("#f7f5f2")
    GREEN = colors.HexColor("#dcfce7")
    DGREEN= colors.HexColor("#16a34a")
    RED   = colors.HexColor("#fee2e2")
    WHITE = colors.white
    AMBER = colors.HexColor("#fef3c7")
    # Back-compat aliases (older references) ↓
    BLUE  = CHAR
    LBLUE = CREAM

    H1 = ParagraphStyle("H1",parent=styl["Heading1"],fontSize=20,textColor=CHAR,
                        spaceAfter=4,fontName="Helvetica-Bold",leading=24)
    H2 = ParagraphStyle("H2",parent=styl["Heading2"],fontSize=12,textColor=ORANGE,
                        spaceAfter=3,spaceBefore=12,fontName="Helvetica-Bold")
    SM = ParagraphStyle("SM",parent=styl["Normal"],fontSize=8,leading=11,textColor=CHAR)
    FT = ParagraphStyle("FT",parent=styl["Normal"],fontSize=7,
                         textColor=colors.HexColor("#888888"),alignment=TA_CENTER)
    RI = ParagraphStyle("RI",parent=styl["Normal"],fontSize=8,alignment=TA_RIGHT)

    def ts(extra=None):
        base=[("BACKGROUND",(0,0),(-1,0),GOLD),("TEXTCOLOR",(0,0),(-1,0),CHAR),
              ("FONTNAME",(0,0),(-1,0),"Helvetica-Bold"),("FONTSIZE",(0,0),(-1,-1),8),
              ("ROWBACKGROUNDS",(0,1),(-1,-1),[WHITE,CREAM]),
              ("GRID",(0,0),(-1,-1),0.4,colors.HexColor("#e0d9cc")),
              ("LINEBELOW",(0,0),(-1,0),1,DORANGE),
              ("PADDING",(0,0),(-1,-1),4),("VALIGN",(0,0),(-1,-1),"MIDDLE")]
        if extra: base.extend(extra)
        return TableStyle(base)

    def r2(v,dp=2):
        try: return round(float(v),dp)
        except: return v or "—"

    def sec(t):
        return [Paragraph(t,H2),
                HRFlowable(width="100%",thickness=1.2,color=ORANGE,spaceAfter=5)]

    story = []

    # ── Logo + Cover ──────────────────────────────────────────────────────────
    # Gridworks logo — embedded offline PNG (no network, no cairosvg needed).
    logo_elem = None
    try:
        import base64 as _b64
        logo_buf = io.BytesIO(_b64.b64decode(LOGO_B64))
        _w = 1.9 * inch
        _h = _w * (310.0 / 640.0)   # preserve aspect ratio
        img = Image(logo_buf, width=_w, height=_h)
        img.hAlign = "RIGHT"
        logo_elem = img
    except Exception:
        logo_elem = None

    # Fallback: draw styled text logo block (brand colors)
    if logo_elem is None:
        from reportlab.platypus import Table as _T, TableStyle as _TS
        logo_box = _T(
            [[Paragraph('<b><font color="#404040" size="13">grid</font>'
                        '<font color="#E2792B" size="13">WORKS</font></b>',
                        ParagraphStyle("lb",parent=styl["Normal"],
                                       alignment=TA_CENTER,spaceAfter=0))]],
            colWidths=[1.5*inch])
        logo_box.setStyle(_TS([
            ("BACKGROUND",(0,0),(-1,-1),CREAM),
            ("PADDING",(0,0),(-1,-1),8),
            ("ALIGN",(0,0),(-1,-1),"CENTER"),
        ]))
        logo_elem = logo_box

    # Header row: title far left, logo far right — spans the full page width
    # so both ends line up with the orange underline beneath.
    hdr_table = Table(
        [[Paragraph("Solar PV Basis of Design", H1), logo_elem]],
        colWidths=[W - 2.5*inch, 2.5*inch]
    )
    hdr_table.setStyle(TableStyle([
        ("VALIGN",(0,0),(-1,-1),"MIDDLE"),
        ("ALIGN",(0,0),(0,0),"LEFT"),
        ("ALIGN",(1,0),(1,0),"RIGHT"),
        ("PADDING",(0,0),(-1,-1),0),
    ]))
    story.append(hdr_table)
    story.append(HRFlowable(width="100%",thickness=2.5,color=ORANGE,spaceAfter=8))

    # Project info block
    proj_rows = [
        ["Project Name:",  project_name,  "Project Number:", project_num or "—"],
        ["Engineer:",      engineer or "—","Date:",          proj_date],
        ["Site Location:", inputs.get("site_location","—"), "", ""],
    ]
    proj_tbl = Table(proj_rows, colWidths=[0.15*W,0.35*W,0.15*W,0.35*W])
    proj_tbl.setStyle(TableStyle([
        ("FONTNAME",(0,0),(0,-1),"Helvetica-Bold"),
        ("FONTNAME",(2,0),(2,-1),"Helvetica-Bold"),
        ("FONTSIZE",(0,0),(-1,-1),9),
        ("TEXTCOLOR",(0,0),(0,-1),DORANGE),
        ("TEXTCOLOR",(2,0),(2,-1),DORANGE),
        ("TEXTCOLOR",(1,0),(1,-1),CHAR),
        ("TEXTCOLOR",(3,0),(3,-1),CHAR),
        ("PADDING",(0,0),(-1,-1),4),
        ("ROWBACKGROUNDS",(0,0),(-1,-1),[CREAM,WHITE]),
        ("GRID",(0,0),(-1,-1),0.3,colors.HexColor("#ead9c2")),
        ("SPAN",(1,2),(3,2)),
    ]))
    story.append(proj_tbl)
    story.append(Spacer(1,0.15*inch))

    # ══ 1. PV Module ══════════════════════════════════════════════════════════
    story.append(KeepTogether(sec("1. PV Module") + [Table([
        ["Parameter","Value","Parameter","Value"],
        ["Module Model", Paragraph(str(inputs.get("module_name","—") or "—"), SM),
         "Technology",        inputs.get("mod_tech","—")],
        ["Module Power (W)",  inputs.get("module_w","—"),  "Max System V (V)", inputs.get("mod_max_sys_v","—")],
        ["Voc STC (V)",       inputs.get("voc_stc","—"),   "Isc STC (A)",       inputs.get("isc_stc","—")],
        ["Vmp STC (V)",       inputs.get("vmp_stc","—"),   "Imp STC (A)",       inputs.get("imp_stc","—")],
        ["β Voc (%/°C)",      inputs.get("beta_voc_pct","—"),"α Isc (%/°C)",   inputs.get("alpha_isc_pct","—")],
        ["γ Pmax (%/°C)",     inputs.get("gamma_pmax_pct","—"),"Dimensions (mm)",
         f"{inputs.get('mod_length_mm','—')} × {inputs.get('mod_width_mm','—')}"],
    ],colWidths=[0.27*W,0.23*W,0.27*W,0.23*W],style=ts())]))

    # ══ 2. Inverter & Power System ════════════════════════════════════════════
    story.append(KeepTogether(sec("2. Inverter & Power System") + [Table([
        ["Parameter","Value","Parameter","Value"],
        ["Inverter Model", Paragraph(str(inputs.get("inverter_name","—") or "—"), SM),
         "Inverter Output (kV)",   inputs.get("inverter_output_kv","—")],
        ["Inverter MVA",           inputs.get("inv_mva","—"),      "Inverter Max Vdc (V)",   inputs.get("inverter_max_vdc","—")],
        ["Inverter Max Isc (A)",   inputs.get("inverter_max_isc","—"),"Inverter PF",          inputs.get("inv_pf","—")],
        ["Inverter Efficiency (%)",inputs.get("inv_efficiency","—"),  "GSU Efficiency (%)",   inputs.get("gsu_efficiency","—")],
        ["GSU Impedance (%)",      inputs.get("gsu_impedance","—"),  "MV Cable Loss (%)",     inputs.get("mv_cable_loss_pct","—")],
        ["MVT Efficiency (%)",     inputs.get("mvt_efficiency","—"), "MVT Impedance (%)",     inputs.get("mvt_impedance","—")],
        ["POI Power (MW)",         inputs.get("poi_mw","—"),         "POI Power Factor",      inputs.get("power_factor","—")],
        ["Modules per String",     inputs.get("modules_per_string","—"), "LBD Rating (A)",   inputs.get("lbd_rating_a","—")],
        ["Rows per LBD",           inputs.get("rows_per_lbd","—"),   "Inverter Max Str.",     inputs.get("inv_max_strings","—")],
    ],colWidths=[0.27*W,0.23*W,0.27*W,0.23*W],style=ts())]))

    # ══ 3. Power Flow ═════════════════════════════════════════════════════════
    story.append(KeepTogether(sec("3. Power Flow (POI → GSU → MV Cable → MVT → Inverter)") + [Table([
        ["Stage","MW","MVAR","MVA"],
        ["POI",         r2(sizing.get("poi_mw")),    r2(sizing.get("poi_mvar")),  r2(sizing.get("poi_mva"))],
        ["GSU Input",   r2(sizing.get("gsu_mw")),    r2(sizing.get("gsu_mvar")),  r2(sizing.get("gsu_mva"))],
        ["MV Cable",    r2(sizing.get("cable_mw")),  r2(sizing.get("cable_mvar")),r2(sizing.get("cable_mva"))],
        ["MVT Input",   r2(sizing.get("mvt_mw")),    r2(sizing.get("mvt_mvar")),  r2(sizing.get("mvt_mva"))],
        ["Inv (per unit)",r2(sizing.get("inv_mw_each"),4),r2(sizing.get("inv_mvar_each"),4),inputs.get("inv_mva","—")],
    ],colWidths=[0.40*W,0.20*W,0.20*W,0.20*W],style=ts())]))

    # ══ 4. Inverter Quantity ══════════════════════════════════════════════════
    n_gov = sizing.get("num_inverters","—")
    story.append(KeepTogether(sec("4. Inverter Quantity Requirements") + [Table([
        ["Basis","No. of Inverters"],
        ["INV MW",  sizing.get("n_by_mw","—")],
        ["INV MVAR",sizing.get("n_by_mvar","—")],
        ["INV MVA", sizing.get("n_by_mva","—")],
        ["No. INV (GOVERNING)", n_gov],
    ],colWidths=[0.60*W,0.40*W],
    style=ts([("BACKGROUND",(0,4),(-1,4),GREEN),
              ("FONTNAME",(0,4),(-1,4),"Helvetica-Bold"),
              ("FONTSIZE",(1,4),(1,4),11)]))]))

    # ══ 5. Voltage & Current Checks ═══════════════════════════════════════════
    voc_pass = sizing.get("voc_check_pass",False)
    story.append(KeepTogether(sec("5. Voltage & Current Checks  (NEC 690)") + [Table([
        ["Parameter","Value"],
        ["Voc corrected at T_min", str(r2(sizing.get("voc_corrected"),3))+" V"],
        ["System Voc",             str(r2(sizing.get("system_voc"),2))+" V"],
        ["NEC 690.7 Check",        "PASS" if voc_pass else "FAIL"],
        ["Isc corrected at T_max", str(r2(sizing.get("isc_corrected"),4))+" A"],
        ["Isc × 1.25 (NEC 690.8)",str(r2(sizing.get("isc_nec_690_8"),3))+" A"],
        ["Optimal Strings/PCS",    str(sizing.get("strings_per_pcs","—"))],
        ["Total PCS Output",       str(r2(sizing.get("total_pcs_mw"),3))+" MW"],
        ["DC/AC Ratio",            str(r2(sizing.get("dc_ac_ratio"),4))],
    ],colWidths=[0.60*W,0.40*W],
    style=ts([("TEXTCOLOR",(1,3),(1,3),DGREEN if voc_pass else colors.HexColor("#b91c1c")),
              ("BACKGROUND",(1,3),(1,3),GREEN if voc_pass else RED),
              ("FONTNAME",(1,3),(1,3),"Helvetica-Bold")]))]))

    # ══ PAGE 2: MV CABLE SCHEDULE ═══════════════════════════════════════════
    story.append(PageBreak())
    story.append(Paragraph("MV Cable Schedule", H1))
    story.append(HRFlowable(width="100%",thickness=2.5,color=ORANGE,spaceAfter=8))

    # 6. System Parameters
    story.append(KeepTogether(sec("6. MV System Parameters") + [Table([
        ["Parameter","Value","Parameter","Value"],
        ["PCS KVA",        cable_params.get("cs_pcs_kva","—"),  "AC Voltage (kV)",  cable_params.get("cs_ac_kv","—")],
        ["System MW",      cable_params.get("cs_system_mw","—"),"Installation",     cable_params.get("cs_installation","—")],
        ["Number of PCS",  cable_params.get("cs_num_pcs","—"),  "",""],
    ],colWidths=[0.27*W,0.23*W,0.27*W,0.23*W],style=ts())]))

    # 7. Feeder Quantities
    if feeder_table:
        story.extend(sec("7. Feeder Quantities"))
        fhdr = [["Feeder #","Feeder Label","# of PCS","Feeder Current (A)"]]
        for f in feeder_table:
            fhdr.append([str(f.get("num","")), f.get("label",""),
                         str(f.get("nPcs","")), str(f.get("currentA",""))])
        story.append(Table(fhdr, colWidths=[0.15*W,0.32*W,0.21*W,0.32*W],style=ts()))

    # 8. MV Cable Runs
    story.extend(sec("8. MV Cable Runs"))
    # Cable runs come from the live input table rows passed by JS
    if cable_runs:
        computed = _compute_cable_rows(cable_runs)

        # --- header cells as Paragraphs so multi-word labels wrap cleanly ---
        _hs = ParagraphStyle('ch', fontName='Helvetica-Bold', fontSize=6.5,
                             leading=8, textColor=CHAR,
                             alignment=TA_CENTER, spaceAfter=0, spaceBefore=0)
        _hl = ParagraphStyle('chl', fontName='Helvetica-Bold', fontSize=6.5,
                             leading=8, textColor=CHAR,
                             alignment=TA_LEFT, spaceAfter=0, spaceBefore=0)
        ch = [[
            Paragraph("FROM",         _hl),
            Paragraph("TO",           _hl),
            Paragraph("# PCS",        _hs),
            Paragraph("KVA",          _hs),
            Paragraph("kV",           _hs),
            Paragraph("CURR.<br/>(A)", _hs),
            Paragraph("MV CABLE",     _hs),
            Paragraph("LEN.<br/>(FT)", _hs),
            Paragraph("AMP.<br/>(A)", _hs),
            Paragraph("INSTALL.",     _hs),
            Paragraph("LOAD<br/>%",   _hs),
            Paragraph("R<br/>Ω/KFT",  _hs),
            Paragraph("V-DROP<br/>%", _hs),
        ]]
        run_extra = []
        first_sub_seen = False   # no separator before the first feeder group

        for r in computed:
            lp  = r["loading_pct"]
            is_sub = str(r.get("to_label","")).strip().upper() == "SUB"
            ch.append([
                r["from_label"], r["to_label"],
                str(r["n_pcs"]), str(r["pcs_kva"]),
                str(r["ac_kv"]),
                f"{r['current_a']:.1f}", r["cable_type"],
                str(r["circuit_length_ft"]),
                str(r["ampacity_a"]), r["installation"],
                f"{lp:.1f}%", str(r["r_ohm_kft"]), f"{r['v_drop_pct']:.4f}%",
            ])
            i = len(ch) - 1    # current row index in table
            if is_sub:
                if first_sub_seen:
                    # insert a thin orange-tinted empty separator row between feeder groups
                    ch.append([""] * 13)
                    sep_i = len(ch) - 1
                    run_extra += [
                        ("BACKGROUND", (0, sep_i), (-1, sep_i), colors.HexColor("#fef0e6")),
                        ("LINEABOVE",  (0, sep_i), (-1, sep_i), 1.5, ORANGE),
                        ("LINEBELOW",  (0, sep_i), (-1, sep_i), 0.3, colors.HexColor("#e0d9cc")),
                        ("TOPPADDING",    (0, sep_i), (-1, sep_i), 3),
                        ("BOTTOMPADDING", (0, sep_i), (-1, sep_i), 3),
                    ]
                first_sub_seen = True
            if lp > 84:
                run_extra.append(("BACKGROUND", (10,i),(10,i), RED))
            elif lp > 75:
                run_extra.append(("BACKGROUND", (10,i),(10,i), AMBER))

        run_style = [
            ("BACKGROUND",(0,0),(-1,0),GOLD),("TEXTCOLOR",(0,0),(-1,0),CHAR),
            ("LINEBELOW",(0,0),(-1,0),1,DORANGE),
            ("FONTNAME",(0,1),(-1,-1),"Helvetica"),
            ("FONTSIZE",(0,1),(-1,-1),7.5),
            ("ROWBACKGROUNDS",(0,1),(-1,-1),[WHITE,CREAM]),
            ("GRID",(0,0),(-1,-1),0.3,colors.HexColor("#e0d9cc")),
            ("TOPPADDING",(0,0),(-1,0),4),("BOTTOMPADDING",(0,0),(-1,0),4),
            ("TOPPADDING",(0,1),(-1,-1),3),("BOTTOMPADDING",(0,1),(-1,-1),3),
            ("LEFTPADDING",(0,0),(-1,-1),3),("RIGHTPADDING",(0,0),(-1,-1),3),
            ("VALIGN",(0,0),(-1,-1),"MIDDLE"),
            ("WORDWRAP",(0,1),(-1,-1),True),
            # FROM / TO left-aligned; numerics centered
            ("ALIGN",(0,1),(1,-1),"LEFT"),
            ("ALIGN",(2,1),(-1,-1),"CENTER"),
        ] + run_extra

        # Column widths — tuned so each header fits without overflow
        # FROM  TO   #PCS  KVA   kV   CURR  CABLE  LEN   AMP   INST  LOAD  R    VDROP
        col_ratio = [1.10, 0.85, 0.45, 0.52, 0.38, 0.68, 1.30, 0.68, 0.68, 1.05, 0.68, 0.62, 0.72]
        _rt = sum(col_ratio)
        col_w = [doc.width * r / _rt for r in col_ratio]
        story.append(Table(ch, colWidths=col_w, repeatRows=1,
                           style=TableStyle(run_style)))
    else:
        story.append(Paragraph("No cable runs entered.", SM))

    # 9. Cable Quantities by Type
    if cable_runs:
        story.extend(sec("9. MV Cable Quantities by Type"))
        CTYPES = ['4/0 AL','500 KCMIL AL','750 KCMIL AL','1000 KCMIL AL','1250 KCMIL AL']
        len_by = {t:0 for t in CTYPES}
        for row in cable_runs:
            t   = row.get("cable_type","4/0 AL")
            lft = float(row.get("circuit_length_ft") or 0)
            if lft > 0 and t in len_by:
                len_by[t] += (lft + 20) * 1.10
        used = [t for t in CTYPES if len_by[t] > 0]
        if used:
            qty_rows = [["Cable Type", "Direct Bury Cable Length (single phase, ft)", "Direct Bury Cable Length Total (x3 phases, ft)"]]
            for t in used:
                sp = len_by[t]
                qty_rows.append([t, f"{sp:.0f}", f"{sp*3:.0f}"])
            story.append(Table(qty_rows,
                colWidths=[0.30*W, 0.35*W, 0.35*W],
                style=ts()))

    # ══ Single Line Diagram (MV Collector) ═══════════════════════════════════
    sld_svg = data.get("sld_svg")
    if sld_svg and "<svg" in sld_svg:
        try:
            import tempfile, os as _os
            from svglib.svglib import svg2rlg
            tf = tempfile.NamedTemporaryFile(delete=False, suffix=".svg", mode="w", encoding="utf-8")
            tf.write(sld_svg); tf.close()
            drawing = svg2rlg(tf.name)
            _os.unlink(tf.name)
            if drawing is not None and drawing.width and drawing.height:
                max_w = W
                max_h = doc.height - 0.9 * inch          # leave room for the title
                scale = min(max_w / drawing.width, max_h / drawing.height)
                if scale > 1: scale = 1.0                 # don't upscale small diagrams
                drawing.scale(scale, scale)
                drawing.width  *= scale
                drawing.height *= scale
                drawing.hAlign = "CENTER"
                story.append(PageBreak())
                story.append(Paragraph("Single Line Diagram", H1))
                story.append(HRFlowable(width="100%", thickness=2.5, color=ORANGE, spaceAfter=8))
                story.extend(sec("MV Collector — One-Line"))
                story.append(drawing)
        except Exception:
            pass   # never let a diagram issue break the PDF

    # ══ Bill of Materials (Project Balance of System) ════════════════════════
    bom_in = data.get("bom")
    if bom_in:
        if not bom_in.get("cable_runs"):
            bom_in["cable_runs"] = data.get("cable_runs", [])
        try:
            bom = calc_bom(bom_in)
        except Exception:
            bom = None
        if bom and bom.get("rows"):
            story.append(PageBreak())
            story.append(Paragraph("Bill of Materials", H1))
            story.append(HRFlowable(width="100%", thickness=2.5, color=ORANGE, spaceAfter=8))
            story.extend(sec("Project Balance of System"))

            HLO = colors.HexColor("#FBE3C8")   # light-orange for input cells
            bom_tbl = [["EQUIPMENT", "DESCRIPTION", "QTY", "UNITS"]]
            bom_style = [
                ("BACKGROUND",(0,0),(-1,0),GOLD), ("TEXTCOLOR",(0,0),(-1,0),CHAR),
                ("FONTNAME",(0,0),(-1,0),"Helvetica-Bold"),
                ("FONTSIZE",(0,0),(-1,-1),8),
                ("LINEBELOW",(0,0),(-1,0),1,DORANGE),
                ("GRID",(0,0),(-1,-1),0.3,colors.HexColor("#e0d9cc")),
                ("PADDING",(0,0),(-1,-1),4),
                ("VALIGN",(0,0),(-1,-1),"MIDDLE"),
                ("FONTNAME",(0,1),(0,-1),"Helvetica-Bold"),
                ("ALIGN",(2,0),(3,-1),"CENTER"),
            ]
            last_eq = None
            for i, r in enumerate(
                    [x for x in bom["rows"] if x.get("qty") not in (None, "", 0)],
                    start=1):
                eq = r["equipment"] if r["equipment"] != last_eq else ""
                last_eq = r["equipment"]
                q = r.get("qty")
                qtxt = "" if q in (None, "") else (f"{q:,}" if isinstance(q, (int, float)) else str(q))
                bom_tbl.append([eq, r["description"], qtxt, r.get("units", "")])
                # white / cream alternating rows (no input-cell highlights in PDF)
                bg = WHITE if (i % 2 == 1) else CREAM
                bom_style.append(("BACKGROUND",(0,i),(-1,i),bg))
            story.append(Table(bom_tbl,
                colWidths=[0.24*W, 0.55*W, 0.12*W, 0.09*W],
                repeatRows=1,
                style=TableStyle(bom_style)))

    # ══ Footer ════════════════════════════════════════════════════════════════
    story.append(Spacer(1,0.3*inch))
    story.append(HRFlowable(width="100%",thickness=1.5,color=ORANGE,spaceAfter=3))
    story.append(Paragraph(
        f"Gridworks Inc.  |  {project_name}  |  {proj_date}  |  NEC 690 / IEC 62738  |  For engineering reference only  |  Developed by Kirlos Mansour",
        FT))

    # ══ Running header / footer (per-page, drawn on canvas) ═══════════════════
    from reportlab.lib.utils import ImageReader
    import base64 as _b64h
    _logo_reader = None
    try:
        _logo_reader = ImageReader(io.BytesIO(_b64h.b64decode(LOGO_B64)))
    except Exception:
        _logo_reader = None

    _hdr_title = "SOLAR PV BASIS OF DESIGN"
    _hdr_left  = (project_name or "").upper()[:48]
    _o = colors.HexColor("#E2792B"); _c = colors.HexColor("#6b6b6b")

    def _foot(c, doc):
        c.saveState()
        w, h = doc.pagesize
        c.setFont("Helvetica", 7.5)
        c.setFillColor(_c)
        c.drawRightString(w - 36, 22, f"Page | {doc.page}")
        c.restoreState()

    def _head(c, doc):
        c.saveState()
        w, h = doc.pagesize
        top = h - 30
        c.setFont("Helvetica", 7.5)
        c.setFillColor(_c)
        c.drawString(36, top, _hdr_left)
        c.drawCentredString(w/2.0, top, _hdr_title)
        if _logo_reader is not None:
            lh = 20.0; lw = lh * (640.0/310.0)
            try: c.drawImage(_logo_reader, w-36-lw, top-7, width=lw, height=lh, mask="auto")
            except Exception: pass
        c.setStrokeColor(_o); c.setLineWidth(1)
        c.line(36, top-10, w-36, top-10)
        c.restoreState()

    def _first_page(c, doc):
        _foot(c, doc)                # cover page: footer only (no running header)

    def _later_pages(c, doc):
        _head(c, doc); _foot(c, doc)

    doc.build(story, onFirstPage=_first_page, onLaterPages=_later_pages)
    buf.seek(0)
    safe = "".join(c for c in project_name if c.isalnum() or c in " _-").strip()
    return send_file(buf, mimetype="application/pdf", as_attachment=True,
                     download_name=f"{safe}_PV_{datetime.date.today()}.pdf")


# ── API: MV Cable Runs → Excel ────────────────────────────────────────────────

@app.route("/api/export/cable_xlsx", methods=["POST"])
def export_cable_xlsx():
    from openpyxl import Workbook
    from openpyxl.styles import Font, PatternFill, Alignment
    data        = request.get_json(force=True)
    cable_runs  = data.get("cable_runs", [])
    proj        = data.get("project_name", "Solar PV Design")
    rows        = _compute_cable_rows(cable_runs)

    wb = Workbook()
    ws = wb.active
    ws.title = "MV Cable Runs"

    GOLD  = PatternFill("solid", start_color="E2C560")
    CREAM = PatternFill("solid", start_color="FBF3E6")
    RED_F = PatternFill("solid", start_color="FFCCCC")
    AMB_F = PatternFill("solid", start_color="FFE599")

    headers = ["FROM","TO","NO. PCS","PCS KVA","AC kV","CURRENT A",
               "MV CABLE","LENGTH FT","AMPACITY A","INSTALLATION","LOADING %","R Ohm/KFT","V-DROP %"]
    col_w   = [12, 12, 8, 8, 8, 10, 15, 10, 10, 14, 10, 10, 10]

    for ci, h in enumerate(headers, 1):
        c = ws.cell(row=1, column=ci, value=h)
        c.font      = Font(bold=True, name="Arial", size=9)
        c.fill      = GOLD
        c.alignment = Alignment(horizontal="center", wrap_text=True)
        ws.column_dimensions[c.column_letter].width = col_w[ci-1]
    ws.row_dimensions[1].height = 24

    first_sub_seen = False
    current_row = 2
    for r in rows:
        is_sub = str(r.get("to_label","")).strip().upper() == "SUB"
        if is_sub:
            if first_sub_seen:
                # insert an empty separator row between feeder groups
                current_row += 1
            first_sub_seen = True

        vals = [r["from_label"], r["to_label"], r["n_pcs"], r["pcs_kva"],
                r["ac_kv"], r["current_a"], r["cable_type"], r["circuit_length_ft"],
                r["ampacity_a"], r["installation"], r["loading_pct"], r["r_ohm_kft"], r["v_drop_pct"]]
        ri = current_row
        alt = (ri % 2 == 0)
        for ci, v in enumerate(vals, 1):
            c = ws.cell(row=ri, column=ci, value=v)
            c.font      = Font(name="Arial", size=9)
            c.alignment = Alignment(horizontal="left" if ci <= 2 else "center")
            if ci == 11:
                lp = r["loading_pct"]
                c.fill = RED_F if lp > 84 else (AMB_F if lp > 75 else (CREAM if alt else PatternFill()))
            elif alt:
                c.fill = CREAM
        current_row += 1

    buf = io.BytesIO(); wb.save(buf); buf.seek(0)
    safe = "".join(c for c in proj if c.isalnum() or c in " _-").strip()
    return send_file(buf,
        mimetype="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
        as_attachment=True, download_name=f"{safe}_CableRuns_{datetime.date.today()}.xlsx")


# ── API: BOM → Excel ──────────────────────────────────────────────────────────

@app.route("/api/export/bom_xlsx", methods=["POST"])
def export_bom_xlsx():
    from openpyxl import Workbook
    from openpyxl.styles import Font, PatternFill, Alignment
    data = request.get_json(force=True)
    if not data.get("cable_runs"):
        data["cable_runs"] = []
    bom  = calc_bom(data)
    # filter zero/blank rows
    rows = [r for r in bom["rows"] if r.get("qty") not in (None, "", 0)]

    wb = Workbook()
    ws = wb.active
    ws.title = "Bill of Materials"

    GOLD  = PatternFill("solid", start_color="E2C560")
    CREAM = PatternFill("solid", start_color="FBF3E6")
    HLO   = PatternFill("solid", start_color="FBE3C8")

    for ci, h in enumerate(["EQUIPMENT","DESCRIPTION","QTY","UNITS"], 1):
        c = ws.cell(row=1, column=ci, value=h)
        c.font      = Font(bold=True, name="Arial", size=10)
        c.fill      = GOLD
        c.alignment = Alignment(horizontal="center")
    ws.column_dimensions["A"].width = 28
    ws.column_dimensions["B"].width = 55
    ws.column_dimensions["C"].width = 12
    ws.column_dimensions["D"].width = 10

    last_eq = None
    for ri, r in enumerate(rows, 2):
        eq       = r["equipment"] if r["equipment"] != last_eq else ""
        last_eq  = r["equipment"]
        alt      = (ri % 2 == 1)
        input_hl = r.get("hl") in ("qty", "row")
        q = r.get("qty")

        for ci, v in enumerate([eq, r["description"], q, r.get("units","")], 1):
            c = ws.cell(row=ri, column=ci, value=v)
            c.font = Font(name="Arial", size=9, bold=(ci == 1 and bool(eq)))
            c.alignment = Alignment(horizontal="left" if ci <= 2 else "center")
            if input_hl and ci >= 3:
                c.fill = HLO
            elif alt:
                c.fill = CREAM

    buf = io.BytesIO(); wb.save(buf); buf.seek(0)
    return send_file(buf,
        mimetype="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
        as_attachment=True, download_name=f"BOM_{datetime.date.today()}.xlsx")


