# ── API: Server-side KMZ extraction (fallback if JSZip not available) ─────────

@app.route("/api/extract_module_pdf", methods=["POST"])
def extract_module_pdf():
    """Extract PV module electrical parameters from an uploaded datasheet PDF using Claude."""
    import base64, json as _json, os
    if "file" not in request.files:
        return jsonify({"ok": False, "error": "No file uploaded"}), 400
    f = request.files["file"]
    if not f.filename.lower().endswith(".pdf"):
        return jsonify({"ok": False, "error": "File must be a PDF"}), 400

    # API key: try env var first, then request param (user-supplied)
    api_key = os.environ.get("ANTHROPIC_API_KEY") or request.form.get("api_key", "").strip()
    if not api_key:
        return jsonify({"ok": False, "error": "no_key",
                        "message": "No Anthropic API key found. Please enter your API key."}), 200

    pdf_b64 = base64.b64encode(f.read()).decode("utf-8")
    try:
        import anthropic
        client = anthropic.Anthropic(api_key=api_key)
        msg = client.messages.create(
            model="claude-sonnet-4-20250514",
            max_tokens=2000,
            messages=[{
                "role": "user",
                "content": [
                    {
                        "type": "document",
                        "source": {"type": "base64", "media_type": "application/pdf", "data": pdf_b64}
                    },
                    {
                        "type": "text",
                        "text": (
                            "Extract all PV module power variants from this datasheet (STC conditions only).\n"
                            "Return ONLY a valid JSON array — no markdown, no explanation.\n"
                            "Each element must have these fields:\n"
                            '  "model": full model name string,\n'
                            '  "pmax": number (W),\n'
                            '  "voc": number (V),\n'
                            '  "isc": number (A),\n'
                            '  "vmpp": number (V),\n'
                            '  "impp": number (A),\n'
                            '  "efficiency": number (%, e.g. 23.51),\n'
                            '  "beta_voc": number (positive %/°C magnitude for Voc),\n'
                            '  "alpha_isc": number (positive %/°C magnitude for Isc),\n'
                            '  "gamma_pmax": number (positive %/°C magnitude for Pmax),\n'
                            '  "length_mm": number,\n'
                            '  "width_mm": number,\n'
                            '  "max_sys_v": number (V),\n'
                            '  "technology": string\n'
                            "If a field is not in the datasheet, use null.\n"
                            "Sort variants from highest to lowest Pmax."
                        )
                    }
                ]
            }]
        )
        raw = msg.content[0].text.strip()
        if raw.startswith("```"):
            lines = raw.split("\n")
            raw = "\n".join(lines[1:])
        if raw.endswith("```"):
            raw = raw[:-3].strip()
        modules = _json.loads(raw)
        return jsonify({"ok": True, "modules": modules})
    except ImportError:
        return jsonify({"ok": False, "error": "anthropic package not installed"}), 500
    except Exception as e:
        return jsonify({"ok": False, "error": str(e)}), 500


@app.route("/api/parse_kmz", methods=["POST"])
def api_parse_kmz():
    import zipfile, io as _io
    if "file" not in request.files:
        return jsonify({"ok": False, "error": "No file uploaded"}), 400
    f = request.files["file"]
    raw = f.read()
    fname = f.filename.lower()
    try:
        if fname.endswith(".kmz"):
            with zipfile.ZipFile(_io.BytesIO(raw)) as z:
                kml_name = next(
                    (n for n in z.namelist() if n.lower().endswith(".kml")), None
                )
                if not kml_name:
                    return jsonify({"ok": False, "error": "No .kml found inside KMZ"}), 422
                kml_text = z.read(kml_name).decode("utf-8-sig")
        elif fname.endswith(".kml"):
            kml_text = raw.decode("utf-8-sig")
        else:
            return jsonify({"ok": False, "error": "File must be .kmz or .kml"}), 400
        return jsonify({"ok": True, "kml": kml_text})
    except zipfile.BadZipFile:
        return jsonify({"ok": False, "error": "Invalid KMZ file (bad zip)"}), 422
    except Exception as e:
        return jsonify({"ok": False, "error": str(e)}), 500


