import math as _math

def _dist_km(lat1, lon1, lat2, lon2):
    R = 6371.0
    dlat = _math.radians(lat2 - lat1)
    dlon = _math.radians(lon2 - lon1)
    a = (_math.sin(dlat/2)**2 +
         _math.cos(_math.radians(lat1)) * _math.cos(_math.radians(lat2)) *
         _math.sin(dlon/2)**2)
    return R * 2 * _math.atan2(_math.sqrt(a), _math.sqrt(1 - a))


def _parse_meteo_response(text):
    """ashrae-meteo.info returns JSON that may be BOM-prefixed, double-encoded
    (a JSON string containing JSON), and/or padded with stray characters.
    Try several strategies until one yields a dict."""
    import json as _json
    if isinstance(text, bytes):
        text = text.decode("utf-8-sig", "ignore")
    text = text.lstrip("\ufeff").strip()

    def _coerce(obj):
        # If we decoded a JSON string that itself contains JSON, decode again.
        for _ in range(3):
            if isinstance(obj, str):
                obj = _json.loads(obj)
            else:
                break
        return obj if isinstance(obj, dict) else None

    candidates = []
    s = text.find("{"); e = text.rfind("}")
    if s != -1 and e != -1:
        candidates.append(text[s:e+1])
    candidates.append(text)

    for c in candidates:
        try:
            obj = _coerce(_json.loads(c))
            if obj is not None:
                return obj
        except Exception:
            continue

    # Last resort: unescape backslash sequences then retry slice.
    try:
        unesc = text.encode("utf-8", "ignore").decode("unicode_escape")
        s = unesc.find("{"); e = unesc.rfind("}")
        if s != -1 and e != -1:
            obj = _coerce(_json.loads(unesc[s:e+1]))
            if obj is not None:
                return obj
    except Exception:
        pass
    raise ValueError("could not parse ASHRAE response")


def _num(v):
    try:
        if v is None: return None
        s = str(v).strip()
        if s in ("", "n/a", "N/A", "-", "--"): return None
        return float(s)
    except (TypeError, ValueError):
        return None


# Candidate API bases — the site has moved paths over time, so we try each.
_ASHRAE_BASES = [
    "https://ashrae-meteo.info/v3.0",
    "https://ashrae-meteo.info",
    "http://ashrae-meteo.info/v3.0",
    "http://ashrae-meteo.info",
]

def _ashrae_post(url, params, timeout=12):
    import urllib.request, urllib.parse
    data = urllib.parse.urlencode(params).encode("utf-8")
    req = urllib.request.Request(url, data=data, headers={
        "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) "
                      "AppleWebKit/537.36 (KHTML, like Gecko) "
                      "Chrome/124.0 Safari/537.36",
        "Accept": "application/json, text/javascript, */*; q=0.01",
        "Content-Type": "application/x-www-form-urlencoded; charset=UTF-8",
        "X-Requested-With": "XMLHttpRequest",
        "Origin": "https://ashrae-meteo.info",
        "Referer": "https://ashrae-meteo.info/v3.0/",
    })
    with urllib.request.urlopen(req, timeout=timeout) as resp:
        return resp.read()


def _fetch_ashrae_live(lat, lon, version, trace=None):
    """Query ashrae-meteo.info for the nearest station and its n=20yr
    return-period extreme dry-bulb temperatures (min & max), in SI units.
    Tries each candidate base URL. Returns a dict on success, else None.
    If `trace` (a list) is passed, append step-by-step diagnostics to it."""

    def log(msg):
        if trace is not None:
            trace.append(msg)

    for base in _ASHRAE_BASES:
        try:
            # Step 1 — nearest stations for the coordinates
            raw = _ashrae_post(f"{base}/request_places.php",
                               {"lat": lat, "long": lon, "number": "5",
                                "ashrae_version": version})
            places = _parse_meteo_response(raw)
            stations = places.get("meteo_stations") or []
            log(f"[{base}] v{version} places -> {len(stations)} station(s)")
            if not stations:
                continue
            st0 = stations[0]
            wmo = st0.get("wmo")
            if not wmo:
                log(f"[{base}] first station had no WMO")
                continue

            # Step 2 — full climatic parameters for that station (SI units)
            raw2 = _ashrae_post(f"{base}/request_meteo_parametres.php",
                                {"wmo": wmo, "ashrae_version": version, "si_ip": "SI"})
            meteo = _parse_meteo_response(raw2)
            mstations = meteo.get("meteo_stations") or []
            if not mstations:
                log(f"[{base}] meteo for WMO {wmo} -> empty")
                continue
            s = mstations[0]

            t_max_20 = _num(s.get("n-year_return_period_values_of_extreme_DB_20_max"))
            t_min_20 = _num(s.get("n-year_return_period_values_of_extreme_DB_20_min"))
            if t_max_20 is None or t_min_20 is None:
                log(f"[{base}] WMO {wmo}: 20yr fields missing "
                    f"(keys: {list(s.keys())[:8]}…)")
                continue

            name = (st0.get("station_name") or s.get("station_name") or
                    st0.get("place") or "ASHRAE Station")
            state = st0.get("state") or st0.get("country") or ""
            full_name = f"{name}, {state}".strip().strip(",") if state else name
            slat = _num(st0.get("lat"))  if _num(st0.get("lat"))  is not None else lat
            slon = _num(st0.get("long")) if _num(st0.get("long")) is not None else lon

            log(f"[{base}] OK -> {full_name} WMO {wmo} "
                f"max={t_max_20} min={t_min_20}")
            return {
                "ok": True, "wmo": wmo, "station_name": full_name,
                "lat": slat, "lon": slon,
                "elevation": _num(st0.get("elevation")) or 0,
                "t_max_20": round(t_max_20, 1),
                "t_min_20": round(t_min_20, 1),
                "t_max_50": _num(s.get("n-year_return_period_values_of_extreme_DB_50_max")),
                "t_min_50": _num(s.get("n-year_return_period_values_of_extreme_DB_50_min")),
                "dist_km":  round(_dist_km(lat, lon, slat, slon), 1),
                "period":   f"ASHRAE {version} Handbook Fundamentals",
                "source":   "live",
                "api_base": base,
            }
        except Exception as e:
            log(f"[{base}] v{version} ERROR: {type(e).__name__}: {e}")
            continue
    return None


@app.route("/api/ashrae", methods=["POST"])
def api_ashrae():
    import math as _m
    data = request.get_json(silent=True) or {}
    try:
        lat = float(data.get("lat"))
        lon = float(data.get("lon"))
    except (TypeError, ValueError):
        return jsonify({"ok": False, "error": "lat and lon required"}), 400

    # 1) Try the live ASHRAE source — newest edition first, then 2021.
    trace = []
    for ver in ("2025", "2021"):
        try:
            live = _fetch_ashrae_live(lat, lon, ver, trace=trace)
            if live:
                return jsonify(live)
        except Exception as e:
            trace.append(f"v{ver} top-level error: {e}")
            continue

    # 2) Fallback — nearest station from the embedded offline table.
    def dist(s):
        dlat = _m.radians(s["lat"] - lat)
        dlon = _m.radians(s["lon"] - lon)
        a = _m.sin(dlat/2)**2 + _m.cos(_m.radians(lat))*_m.cos(_m.radians(s["lat"]))*_m.sin(dlon/2)**2
        return 6371 * 2 * _m.atan2(_m.sqrt(a), _m.sqrt(1-a))

    wmo, st = min(ASHRAE_STATIONS.items(), key=lambda x: dist(x[1]))
    return jsonify({
        "ok": True, "wmo": wmo,
        "station_name": st["name"],
        "lat": st["lat"], "lon": st["lon"],
        "elevation": st["elev"],
        "t_max_20": st["t_max_20"],
        "t_min_20": st["t_min_20"],
        "t_mean":   st["t_mean"],
        "dist_km":  round(dist(st), 1),
        "period":   "ASHRAE 2021 (offline table — live lookup unavailable)",
        "source":   "offline",
        "trace":    trace,
    })


@app.route("/api/ashrae/diag", methods=["GET"])
def api_ashrae_diag():
    """Open this in a browser on the live site to see exactly what the
    live ASHRAE lookup does, e.g.:
      /api/ashrae/diag?lat=45.369173&lon=-81.853798
    Returns the full step-by-step trace so failures can be pinpointed."""
    try:
        lat = float(request.args.get("lat", "45.369173"))
        lon = float(request.args.get("lon", "-81.853798"))
    except ValueError:
        return jsonify({"ok": False, "error": "bad lat/lon"}), 400
    trace = []
    result = None
    for ver in ("2025", "2021"):
        try:
            result = _fetch_ashrae_live(lat, lon, ver, trace=trace)
            if result:
                break
        except Exception as e:
            trace.append(f"v{ver} top-level error: {type(e).__name__}: {e}")
    return jsonify({
        "ok": bool(result),
        "input": {"lat": lat, "lon": lon},
        "result": result,
        "trace": trace,
    })


# ── BOM (Bill of Materials) — reproduces the Excel "Schedule Output" sheet ────
_BOM_MV_TYPES = ["4/0 AL", "500 KCMIL AL", "750 KCMIL AL",
                 "1000 KCMIL AL", "1250 KCMIL AL"]

def _bom_num(v, default=0.0):
    try:
        s = str(v).strip()
        if s in ("", "None", "n/a"): return default
        return float(s)
    except (TypeError, ValueError):
        return default

def _bom_e_total(length, count):
    # Excel Schedule Inputs!E: IF(D<=66, 0, ROUNDUP((D + 20*C)*1.1*3, 0))
    import math
    if length <= 66:
        return 0
    return int(math.ceil((length + 20 * count) * 1.1 * 3))

def _bom_aggregate_cables(cable_runs):
    """Per MV cable type: number of runs, total circuit length, and how many
    of those runs connect to the substation (SUB) — used for feeders, elbows
    and sub-terminations, mirroring the Cable Schedule sheet."""
    agg = {t: {"count": 0, "length": 0.0, "sub": 0} for t in _BOM_MV_TYPES}
    for r in (cable_runs or []):
        t = (r.get("cable_type") or "").strip()
        if t not in agg:
            continue
        agg[t]["count"] += 1
        agg[t]["length"] += _bom_num(r.get("circuit_length_ft"), 0.0)
        frm = str(r.get("from_label") or "").strip().upper()
        to  = str(r.get("to_label") or "").strip().upper()
        if frm == "SUB" or to == "SUB":
            agg[t]["sub"] += 1
    return agg

def calc_bom(inp: dict) -> dict:
    """Build the Project Balance of System BOM. Quantities reproduce the
    formulas in the Excel 'Schedule Output' sheet exactly. Cable-derived
    figures come from the project's Cable Schedule; tracker/PCS/other values
    come from sizing + the BOM input fields."""
    import math
    agg = _bom_aggregate_cables(inp.get("cable_runs"))

    isc = _bom_num(inp.get("isc"))
    mps = _bom_num(inp.get("modules_per_string"))
    lbd_rating = _bom_num(inp.get("lbd_rating"), 400.0) or 400.0

    # ── Tracker table → module counts (E=mpr*rows) and rows/LBD (N) ───────────
    tks = []
    for t in (inp.get("trackers") or [])[:3]:
        mpr = _bom_num(t.get("modules_per_row"))
        rc  = _bom_num(t.get("row_count"))
        spr = (mpr / mps) if mps else 0          # strings per row  (M = K/F13)
        row_isc = isc * spr                       # L = Isc * M
        rpl = int(math.floor((lbd_rating / 1.25 / 1.25) / row_isc)) if row_isc > 0 else 0
        tks.append({"desc": t.get("desc", ""), "mpr": mpr, "rc": rc,
                    "modules": int(round(mpr * rc)), "rpl": rpl,
                    "row_length_ft": _bom_num(t.get("row_length_ft"))})
    while len(tks) < 3:
        tks.append({"desc": "", "mpr": 0, "rc": 0, "modules": 0, "rpl": 0})

    pv_total = sum(t["modules"] for t in tks)

    # LBD by tracker type (Excel C8) — note the sheet reuses tracker-2's
    # (rows/LBD, modules-per-row) for both tracker-2 and tracker-3 terms.
    def _sd(a, b): return (a / b) if b else 0
    N1, K1 = tks[0]["rpl"], tks[0]["mpr"]
    N2, K2 = tks[1]["rpl"], tks[1]["mpr"]
    lbd_qty = (_sd(tks[0]["modules"], N1 * K1)
               + _sd(tks[2]["modules"], N2 * K2)
               + _sd(tks[1]["modules"], N2 * K2)) * 1.04
    lbd_qty = int(round(lbd_qty)) if lbd_qty else None

    num_inv = int(_bom_num(inp.get("num_inverters")))
    pcs_count = num_inv                                   # J2

    feeders = inp.get("feeders")
    feeders = int(_bom_num(feeders)) if str(feeders).strip() not in ("", "None") else 0
    if feeders <= 0:                                      # J3 — else derive from SUB runs
        feeders = sum(agg[t]["sub"] for t in _BOM_MV_TYPES)

    sec3 = int(_bom_num(inp.get("sectionalizer_3term")))  # C17
    sec2 = inp.get("sectionalizer_2term")                 # C16 (pure input)
    sec2 = int(_bom_num(sec2)) if str(sec2).strip() not in ("", "None") else None
    fault_pcs_units = inp.get("fault_pcs_units")
    fault_pcs_units = int(_bom_num(fault_pcs_units)) if str(fault_pcs_units).strip() not in ("", "None") else 13
    fault_pcs_qty = inp.get("fault_pcs_qty")
    has_fault_qty = str(fault_pcs_qty).strip() not in ("", "None")

    def opt(v):  # blank input → None
        s = str(v).strip()
        return _bom_num(v) if s not in ("", "None") else None

    dc_cable = opt(inp.get("dc_cable_ft"))
    bore1    = opt(inp.get("bore1_ft"))
    road     = opt(inp.get("road_ft"))
    fence    = opt(inp.get("fence_ft"))

    # ── MV cable rows: qty = count + E_total  (blank if type unused) ──────────
    def mv_qty(t):
        c, L = agg[t]["count"], agg[t]["length"]
        if c == 0 and L == 0:
            return None
        return int(c + _bom_e_total(L, c))
    mv = {t: mv_qty(t) for t in _BOM_MV_TYPES}
    mv_used = [mv[t] for t in ["1000 KCMIL AL", "750 KCMIL AL", "500 KCMIL AL", "4/0 AL"]]
    trench = int(round(sum(v for v in mv_used if v) / 3)) if any(mv_used) else None

    def elbow(t):                                         # 6*count - feeders_using*3
        c = agg[t]["count"]
        if c == 0:
            return None
        return int(6 * c - agg[t]["sub"] * 3)

    sub_cl7_runs = agg["500 KCMIL AL"]["sub"] + agg["750 KCMIL AL"]["sub"]
    sub_cl9_runs = agg["1000 KCMIL AL"]["sub"] + agg["1250 KCMIL AL"]["sub"]
    sub_cl7 = sub_cl7_runs * 3 if (agg["500 KCMIL AL"]["count"] or agg["750 KCMIL AL"]["count"]) else None
    sub_cl9 = sub_cl9_runs * 3 if (agg["1000 KCMIL AL"]["count"] or agg["1250 KCMIL AL"]["count"]) else None

    surge   = feeders * 3 + 4 * 3 if feeders else None
    flt_sub = feeders * 3 if feeders else None
    flt_pcs = int(_bom_num(fault_pcs_qty)) if has_fault_qty else fault_pcs_units * 3
    g_cable = int(pcs_count * (15 + 15 + 25 + 25) + sec3 * 15) if pcs_count else None
    g_rods  = int(pcs_count * 4 + sec3) if pcs_count else None

    R = lambda eq, desc, qty, units, hl=None: {
        "equipment": eq, "description": desc, "qty": qty, "units": units, "hl": hl}

    # ── RACKING rows: format as "rows / modules" + row length rows ────────────
    racking_array_rows = []
    racking_len_rows   = []
    for t in tks:
        rc      = int(t["rc"])      if t["rc"]      else 0
        modules = int(t["modules"]) if t["modules"] else 0
        mpr     = int(t["mpr"])     if t["mpr"]     else 0
        rlen_ft = _bom_num(t.get("row_length_ft"))

        if rc and modules:
            qty_str = f"{rc:,} / {modules:,}"
            racking_array_rows.append(R("RACKING", t["desc"] or "TRACKER", qty_str, "EA"))

        if rlen_ft and rc and mpr:
            rlen_m   = round(rlen_ft / 3.281)
            total_ft = round(rlen_ft * rc)
            total_m  = round(total_ft / 3.281)
            rlen_str = f"{int(rlen_ft):,} ({rlen_m:,}) / {total_ft:,} ({total_m:,})"
            racking_len_rows.append(
                R("RACKING", f"ROW LENGTH / TOTAL ROW LENGTH - {mpr} MODULES", rlen_str, "FT (M)"))

    racking_rows = racking_array_rows + racking_len_rows

    # Combined bore
    bore_out   = bore1 if bore1 else None

    rows = (
        [R("PV MODULES", inp.get("module_model", "FIRST SOLAR SERIES 7, 535W"), pv_total or None, "EA")]
        + racking_rows
        + [
        R("PCS[INVERTER]", inp.get("pcs_model", "SOLAR WARE NINJA PVU-L0840GR-2"), num_inv or None, "EA"),
        R("LOAD BREAK DISCONNECT", "400A, INPUT/1 OUTPUT", lbd_qty, "EA", "qty"),
        R("DC CABLE TO LBD TO INV/PCS", "2P 500 KCMIL AL XHHW-2 (UNDERGROUND CIRCUIT LENGTH)", dc_cable, "FT", "qty"),
        R("MV CABLE", "1000 KCMIL, AL, 1/3 CN, MV-105", mv["1000 KCMIL AL"], "FT"),
        R("MV CABLE", "750 KCMIL, AL, 1/3 CN, MV-105",  mv["750 KCMIL AL"],  "FT"),
        R("MV CABLE", "500 KCMIL, AL, 1/3 CN, MV-105",  mv["500 KCMIL AL"],  "FT"),
        R("MV CABLE", "4/0 AL, 1/3 CN, MV-105",         mv["4/0 AL"],        "FT"),
        R("MV CABLE", "4/0 CU TRENCH GROUND",            trench,              "FT"),
        R("MV CABLE", "MV TRENCH (TOTAL)",                trench,              "FT"),
        R("MV SECTIONALIZERS", "3 PHASE, [2] TERMINAL, 35 KV SECTIONALIZER CABINET",  sec2,        "EA", "qty"),
        R("MV SECTIONALIZERS", "3 PHASE, [3] TERMINAL, 35 KV SECTIONALIZER CABINET",  sec3 or None,"EA"),
        R("MV BORE",  "BORE LENGTH (TOTAL)",              bore_out,            "FT", "qty"),
        R("MV SUB TERMS", "TE CONNECTIVITY ELB-35-610-X-750-200",  elbow("750 KCMIL AL"),  "EA"),
        R("MV SUB TERMS", "TE CONNECTIVITY ELB-35-610-X-500-200",  elbow("500 KCMIL AL"),  "EA"),
        R("MV SUB TERMS", "TE CONNECTIVITY ELB-35-610-X-40-200",   elbow("4/0 AL"),        "EA"),
        R("MV SUB TERMS", "TE CONNECTIVITY ELB-35-610-X-1000-200", elbow("1000 KCMIL AL"), "EA"),
        R("MV SUB TERMS", "TE CONNECTIVITY CSTO-353J-CL7-B3",      sub_cl7,                "EA"),
        R("MV SUB TERMS", "TE CONNECTIVITY CSTO-353J-CL9-B3",      sub_cl9,                "EA"),
        R("MV SURGE ARRESTORS",  "TE CONNECTIVITY ELB-35-600-ARSTR30-W", surge, "EA"),
        R("MV FAULT INDICATORS", "SEL-CR UNDERGROUND CURRENT RESET FAULT INDICATORS - SUBSTATION", flt_sub, "EA"),
        R("MV FAULT INDICATORS", "SEL-TDR UNDERGROUND CURRENT RESET FAULT INDICATORS - PCS",       flt_pcs, "EA", "qty"),
        R("GROUND ELECTRODE CABLE", "4/0 BARE COPPER STRANDED CABLE", g_cable, "FT"),
        R("GROUND RODS",    "3/4\" COPPER CLAD STEEL GROUND ROD, 10' LENGTH", g_rods, "EA"),
        R("ROAD",  "16' ROAD WITH 2' SHOULDER",       road,  "FT", "qty"),
        R("FENCE", "6' CHAIN LINK IN ACCORDANCE WITH CPW", fence, "FT", "qty"),
        ]
    )
    return {"ok": True, "title": "PROJECT BALANCE OF SYSTEM", "rows": rows,
            "feeders": feeders, "pcs_count": pcs_count}


@app.route("/api/bom", methods=["POST"])
def api_bom():
    data = request.get_json(silent=True) or {}
    try:
        return jsonify(calc_bom(data))
    except Exception as e:
        return jsonify({"ok": False, "error": str(e)}), 422


